            };
        };
    };

    if(s.contains(lower;"lives in")){
        let parts=s.split(msg;"lives in ");
        if(parts.len>=2){
            let location=s.trim(parts.get(1));
            let lparts=s.split(location;" ");
            if(lparts.len>0){
                let place=lparts.get(0);
                if(lparts.len>=2){
                    place=s.concat(s.concat(place;" ");lparts.get(1));
                };
                facts=facts.append(s.concat("lives in ";place));
            };
        };
    };

    if(s.contains(lower;"moved to")){
        let parts=s.split(msg;"moved to ");
        if(parts.len>=2){
            let location=s.trim(parts.get(1));
            let lparts=s.split(location;" ");
            if(lparts.len>0){
                let place=lparts.get(0);
                if(lparts.len>=2){
                    place=s.concat(s.concat(place;" ");lparts.get(1));
