        if(parts.len>=2){
            let company=s.trim(parts.get(1));
            let cparts=s.split(company;".");
            if(cparts.len>0){
                facts=facts.append(s.concat("works at ";cparts.get(0)));
            };
        };
    };

    if(s.contains(lower;"has a")){
        let eidx=s.indexof(lower;s.tolower(entity));
        if(eidx>=0){
            let afterentity=s.slice(msg;eidx+entity.len;msg.len);
